UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Get 1 free Sweet Iced Tea when ordering 3 or more drinks (Wednesdays only)', p.description_ja = 'ドリンク3杯以上注文時、スイートアイスティー1杯無料（水曜日のみ）。', p.description_vi = 'Tặng 1 trà đá ngọt khi gọi từ 3 đồ uống trở lên (chỉ thứ Tư).' WHERE pr.store_name_ko = '빽다방' AND p.description = '음료 3개 이상 시키면 달콤 아이스티 1잔(수요일)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Twice a week, get one free pearl topping when purchasing 2 or more drinks.', p.description_ja = '週2回、ドリンク2杯以上購入でタピオカ追加1回無料。', p.description_vi = 'Mỗi tuần 2 lần, mua từ 2 đồ uống trở lên được thêm trân châu miễn phí 1 lần.' WHERE pr.store_name_ko = '공차' AND p.description = '주2번 2잔, 3잔 이상 구매 시 펄 추가 1회 무료';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Get one free topping add-on for purchases between 2:30 PM and 5:30 PM.', p.description_ja = '2:30 PM〜5:30 PMの購入でトッピング追加を1回無料提供。', p.description_vi = 'Tặng 1 lần topping thêm cho giao dịch mua từ 2:30 PM đến 5:30 PM.' WHERE pr.store_name_ko = '부리또집' AND p.description = '오후 2:30~오후 5:30 구매 시 토핑 추가 1회 무료';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For purchases of 30,000 KRW or more (up to 3 receipts combined), choose one: 3 pieces of Youtiao, Cha Pai, or Bing Hong Cha.', p.description_ja = '30,000ウォン以上の購入で、油条3個・茶π・冰紅茶のうち1つを選択。レシートは最大3枚まで合算可能。', p.description_vi = 'Đơn mua từ 30.000 KRW trở lên được chọn 1 trong các món: 3 miếng quẩy Youtiao, Cha Pai hoặc Bing Hong Cha. Có thể gộp tối đa 3 hóa đơn.' WHERE pr.store_name_ko = '샹츠마라' AND p.description = '30000원 이상 구매시(단 영수증 3개 미만) 유토루 3 pcs, 차파이, 삐홍차 중 택 1';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Add 30g of chicken breast or smoked duck topping with a main topping order.', p.description_ja = 'メイントッピング注文時、鶏むね肉または燻製鴨トッピング30gを追加提供。', p.description_vi = 'Khi gọi topping chính, được thêm 30g topping ức gà hoặc vịt hun khói.' WHERE pr.store_name_ko = '포케올데이' AND p.description = '메인 토필 주문시 닭가슴살 또는 훈제오리 토핑 30g 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Visit before 6 PM to receive 500ml cocktail soju, or get free kimchi fried rice for cash payments of 70,000 KRW or more.', p.description_ja = '18時以前の来店でカクテル焼酎500mlを提供、または70,000ウォン以上の現金決済でキムチチャーハン1品を提供。', p.description_vi = 'Đến trước 6 PM được tặng 500ml soju cocktail, hoặc thanh toán tiền mặt từ 70.000 KRW trở lên được tặng 1 phần cơm chiên kimchi.' WHERE pr.store_name_ko = '블루힐' AND p.description = '18시 이전 방문 시 칵테일 소주 500ml 제공, 7만원 이상 현금 결제 시 김치볶음밥 하나 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 bottle of soju for purchases of 50,000 KRW or more (1 bottle per group).', p.description_ja = '50,000ウォン以上の購入で焼酎1本無料（1グループにつき1本）。', p.description_vi = 'Mua từ 50.000 KRW trở lên được tặng 1 chai soju (mỗi nhóm 1 chai).' WHERE pr.store_name_ko = '젠사이야' AND p.description = '오만원 이상 구매시 소주 한 병 무료 *일행당 1병';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Soongsil University pricing: Set A, B, and C available at youth rates.', p.description_ja = 'Set A・B・Cは青少年料金で利用可能。', p.description_vi = 'Set A, B, C áp dụng giá thanh thiếu niên.' WHERE pr.store_name_ko = '놀숲' AND p.description = '숭실대 요금표: SET A, B, C 요금제 성인 -> 청소년 변경';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '15% off game fees with a Naver review within 1 week, including the same day.', p.description_ja = '当日を含む1週間以内のNaverレビューでゲーム料金15%割引。', p.description_vi = 'Giảm 15% phí chơi game khi viết review Naver trong vòng 1 tuần, tính cả ngày sử dụng.' WHERE pr.store_name_ko = '히어로 보드게임카페' AND p.description = '게임비 15% 할인 / 1주일 이내 (당일 포함) 네이버 리뷰';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '1. Americano for 2,000 KRW when ordering through POS before 9 AM
 
 2. Free size upgrade from L to J when purchasing 4 or more drinks on Mondays and Fridays.
 Excludes single-size menu items such as smoothies, crushes, Brown Sugar Jewelry, and Strawberry Jewelry.
 
 3. 10% off group orders of 10 drinks or more.
 Only applies to direct POS payments. Delivery/platform orders such as Baemin, Coupang Eats, and Naver are excluded.', p.description_ja = '1. 9時以前にPOS注文するとアメリカーノ2,000ウォン。
 2. 月・金曜日にドリンク4杯以上購入でL→Jサイズアップ無料。単一サイズメニューは対象外。
 3. ドリンク10杯以上の団体注文は10%割引。店頭POSでの直接決済のみ対象。プラットフォーム注文は対象外。', p.description_vi = '1. Americano giá 2.000 KRW khi đặt qua POS trước 9 AM.
 2. Mua từ 4 đồ uống vào thứ Hai và thứ Sáu được nâng size miễn phí từ L lên J. Không áp dụng cho món chỉ có một size.
 3. Giảm 10% cho đơn nhóm từ 10 đồ uống trở lên. Chỉ áp dụng khi thanh toán trực tiếp tại POS; không áp dụng cho đơn trên nền tảng.' WHERE pr.store_name_ko = '공차' AND p.description = '1. 9시 이전 POS 주문시
아메리카노 2000원 구매

2. 월, 금요일 4잔 이상 구매시
L -> J size up
(단일 사이즈메뉴는 제외-스무디, 크러쉬,브라운슈가 쥬얼리 ,딸기쥬얼리 등등)

3. 10잔 이상 단체 주문시 10%할인
포스에서 직접 결제, 배민 쿠팡이츠 네이버등 플랫폼 결제는 할인적용x';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 bottled soft drink.', p.description_ja = 'ボトル飲料1本を無料提供。', p.description_vi = 'Tặng 1 chai nước ngọt.' WHERE pr.store_name_ko = '광어삼촌' AND p.description = '음료 1병 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 canned soft drink when ordering 3 or more meals.', p.description_ja = '食事メニュー3品以上注文時、缶ドリンク1本を無料提供。', p.description_vi = 'Gọi từ 3 món ăn trở lên được tặng 1 lon nước ngọt.' WHERE pr.store_name_ko = '논두렁갈비' AND p.description = '식사류 3개 이상 주문시 음료 1캔 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '5% off when paying with Toss or KakaoPay (meat dishes only).', p.description_ja = 'TossまたはKakaoPay決済時、肉料理5%割引。', p.description_vi = 'Giảm 5% món thịt khi thanh toán bằng Toss hoặc KakaoPay.' WHERE pr.store_name_ko = '먹돼지' AND p.description = '토스 or 카카오페이 결제 시 5% 할인 (고기류 주문 시에만 해당)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Get one free topping add-on (Double Cheese, Corn, Beans, or Jalapeños) for orders placed between 2:30 PM and 5:30 PM.', p.description_ja = '2:30 PM〜5:30 PMの注文で、ダブルチーズ・コーン・豆・ハラペーニョのうちトッピング1つを無料追加。', p.description_vi = 'Đơn đặt từ 2:30 PM đến 5:30 PM được thêm miễn phí 1 topping: phô mai đôi, bắp, đậu hoặc ớt jalapeño.' WHERE pr.store_name_ko = '부리또집' AND p.description = '2시반에서 5시반 사이 주문 시, 토핑(더블치즈, 옥수수콘, 콩, 할라피뇨) 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 canned soft drink when ordering Dakhanmari or dumpling hot pot according to the number of people.', p.description_ja = 'タッカンマリまたは餃子鍋を人数分注文時、缶ドリンク1本を無料提供。', p.description_vi = 'Gọi dakhanmari hoặc lẩu mandu theo số người được tặng 1 lon nước ngọt.' WHERE pr.store_name_ko = '황새골' AND p.description = '닭한마리, 만두전골 인원 수 맞춰서 주문 시 음료수 한 캔 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For groups of 4 or more, get 1 free canned soft drink. Or, for groups of 4 or more spending 50,000 KRW or more, get 1 free bottle of soju.', p.description_ja = '4人以上で缶ドリンク1本を無料提供。
 また、4人以上で50,000ウォン以上利用時、焼酎1本を無料提供。', p.description_vi = 'Nhóm từ 4 người trở lên được tặng 1 lon nước ngọt.
