UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free rice ball for purchases of 40,000 KRW or more.', p.description_ja = '40,000ウォン以上の購入でおにぎりを無料提供。', p.description_vi = 'Mua từ 40.000 KRW trở lên được tặng cơm nắm.' WHERE pr.store_name_ko = '불타는 소금구이' AND p.description = '4만원 이상 구매 시 주먹밥 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For orders of 20,000 KRW or more, get 2 free drinks. For orders of 30,000 KRW or more, upgrade single items to set menus.', p.description_ja = '20,000ウォン以上の注文でドリンク2杯を無料提供。
 30,000ウォン以上の注文で単品をセットメニューに変更。', p.description_vi = 'Đơn từ 20.000 KRW trở lên được tặng 2 đồ uống.
 Đơn từ 30.000 KRW trở lên được nâng món lẻ thành set menu.' WHERE pr.store_name_ko = '지지고' AND p.description = '2만원 이상 주문 시 음료 2개 제공, 3만원 이상 주문 시 단품을 세트로 변경';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 500ml soft drink for groups of 4 or more.', p.description_ja = '4人以上の来店で1 500ml ソフトドリンクを無料提供。', p.description_vi = 'Nhóm từ 4 người trở lên được tặng 1 500ml nước ngọt.' WHERE pr.store_name_ko = '맛닭꼬' AND p.description = '4인 이상 방문 시 500ml 음료 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free cheese topping when ordering 2 or more servings per table.', p.description_ja = 'テーブルごとに2人前以上注文時、チーズトッピングを無料追加。', p.description_vi = 'Mỗi bàn gọi từ 2 phần trở lên được thêm topping phô mai miễn phí.' WHERE pr.store_name_ko = '코웍 비스트로' AND p.description = '테이블 당 2인분 이상 주문 시 치즈 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Add 30g of chicken breast or smoked duck per menu item.', p.description_ja = 'メニュー1品ごとに、鶏むね肉または燻製鴨30gを追加提供。', p.description_vi = 'Thêm 30g ức gà hoặc vịt hun khói cho mỗi món.' WHERE pr.store_name_ko = '포케올데이' AND p.description = '메뉴당 닭가슴살 or 훈제오리 30g 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1.25L Pepsi Zero for orders of 30,000 KRW or more.', p.description_ja = '30,000ウォン以上の注文でペプシゼロ1.25Lを無料提供。', p.description_vi = 'Đơn từ 30.000 KRW trở lên được tặng 1 chai Pepsi Zero 1,25L.' WHERE pr.store_name_ko = '피자스쿨' AND p.description = '3만원 이상 주문 시 펩시 제로 1.25L 제공';
