UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For groups of 4 or more, choose one per table: 1 500ml soft drink or 4 fried dumplings.', p.description_ja = '4人以上の来店で、テーブルごとに1 500ml ソフトドリンクまたは4 焼き餃子のいずれかを提供。', p.description_vi = 'Nhóm từ 4 người trở lên chọn 1 ưu đãi cho mỗi bàn: 1 500ml nước ngọt hoặc 4 mandu chiên.' WHERE pr.store_name_ko = '취향' AND p.description = '4인 이상 방문 시 테이블 당 음료 500ml or 군만두 4개 중 택 1 제공';
