UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free extra shot in one drink when ordering 2 big-size iced teas or Americanos.', p.description_ja = 'ビッグサイズのアイスティーまたはアメリカーノを2杯注文時、1杯にショット1回無料追加。', p.description_vi = 'Gọi 2 ly trà đá hoặc Americano cỡ lớn được thêm 1 shot miễn phí vào 1 ly.' WHERE pr.store_name_ko = '카페 봄봄' AND p.description = '아이스티 or 아메리카노 빅사이즈 2잔 주문 시 1잔 샷 추가';
