UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For dine-in orders, get one free 500ml soft drink per table when spending 75,000 KRW or more for groups of up to 4, or 85,000 KRW or more for groups of 5 or more.', p.description_ja = '店内注文で、4人以下は75,000ウォン以上、5人以上は85,000ウォン以上の利用時、テーブルごとに500mlドリンク1本を無料提供。', p.description_vi = 'Đơn ăn tại chỗ được tặng 1 nước ngọt 500ml cho mỗi bàn khi chi tiêu từ 75.000 KRW với nhóm tối đa 4 người, hoặc từ 85.000 KRW với nhóm từ 5 người trở lên.' WHERE pr.store_name_ko = '청운음식점' AND p.description = '4인 이하 7만 5천원 / 5인 이하 8만 5천원 방문 주문 시 한 테이블 음료 500ml 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free soybean paste stew per table, plus free steamed egg once when ordering 3 or more meat servings per table.', p.description_ja = 'テーブルごとにテンジャンチゲを提供。さらにテーブルごとに肉3人前以上注文時、茶碗蒸しを1回無料提供。', p.description_vi = 'Mỗi bàn được tặng canh tương đậu. Gọi từ 3 phần thịt trở lên mỗi bàn được tặng thêm 1 lần trứng hấp.' WHERE pr.store_name_ko = '고기스토리' AND p.description = '테이블 당 된장찌개 제공, 테이블 당 고기 3인분 이상 주문 시 계란찜 1회 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free side menu (Bibim Noodles) plus 1 drink when participating in the review event.', p.description_ja = 'レビューイベント参加時、サイドメニュー（ビビン麺）＋ドリンク1杯を無料提供。', p.description_vi = 'Tham gia sự kiện review được tặng món phụ (mì trộn bibim) + 1 đồ uống.' WHERE pr.store_name_ko = '상도동 솥뚜껑' AND p.description = '리뷰이벤트 참여 시 사이드메뉴(비빔면) + 음료 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free fried egg per person, or free steamed egg for groups of 4 or more. Naver receipt review required.', p.description_ja = '1人につき目玉焼き1個、または4人以上で茶碗蒸しを提供。Naverレシートレビュー必須。', p.description_vi = 'Tặng trứng ốp la cho mỗi người, hoặc tặng trứng hấp cho nhóm từ 4 người trở lên. Cần đánh giá hóa đơn Naver.' WHERE pr.store_name_ko = '함지박' AND p.description = '인당 계란후라이 또는 4인 이상 시 계란찜 (네이버 영수증 리뷰 필수)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For orders of 20,000 KRW or more, get 2 free drinks. For orders of 30,000 KRW or more, upgrade all menu items to set menus.', p.description_ja = '20,000ウォン以上の注文でドリンク2杯を無料提供。
 30,000ウォン以上の注文で全メニューをセットメニューに変更。', p.description_vi = 'Đơn từ 20.000 KRW trở lên được tặng 2 đồ uống.
 Đơn từ 30.000 KRW trở lên được nâng toàn bộ menu thành set menu.' WHERE pr.store_name_ko = '지지고' AND p.description = '2만원 이상 주문 시 음료 2개 서비스, 3만원 이상 주문 시 모든 메뉴 세트로 변경';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '10% off all menu items, excluding set menus.', p.description_ja = 'セットメニューを除く全メニュー10%割引。', p.description_vi = 'Giảm 10% toàn bộ menu, không gồm set menu.' WHERE pr.store_name_ko = '에브어이브' AND p.description = '전메뉴 10% 할인 (세트메뉴 제외)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free extra espresso shot for orders of 10,000 KRW or more.', p.description_ja = '10,000ウォン以上の注文でエスプレッソショット1回無料追加。', p.description_vi = 'Đơn từ 10.000 KRW trở lên được thêm 1 shot espresso miễn phí.' WHERE pr.store_name_ko = '블랙&조이커피' AND p.description = '만원 이상 주문 시 샷 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free extra shot once when ordering 2 drinks (2 Big Americanos, or 1 Big Americano plus 1 Iced Tea). 
