UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free chocolate shell, strawberry shell, or granola topping for in-store orders of 18,000 KRW or more.', p.description_ja = '来店注文18,000ウォン以上で、チョコシェル・いちごシェル・グラノーラのうちトッピング1つを無料追加。', p.description_vi = 'Đơn tại cửa hàng từ 18.000 KRW trở lên được chọn thêm miễn phí topping sốt phủ chocolate, sốt phủ dâu hoặc granola.' WHERE pr.store_name_ko = '요거트아이스크림의정석' AND p.description = '18000원 이상 방문 주문 시 초코/딸기쉘 or 그래놀라 토핑 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free Americano with any slice cake purchase.', p.description_ja = 'カットケーキ購入時、アメリカーノ1杯を無料提供。', p.description_vi = 'Mua miếng bánh kem được tặng 1 Americano.' WHERE pr.store_name_ko = '커피나무' AND p.description = '조각케이크 구매 시 아메리카노 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Morning set: Americano + sandwich for 3,500 KRW, plus free size-up for all drinks.', p.description_ja = 'モーニングセット：アメリカーノ＋サンドイッチ3,500ウォン、全ドリンク無料サイズアップ。', p.description_vi = 'Set buổi sáng: Americano + sandwich giá 3.500 KRW, đồng thời nâng size miễn phí cho toàn bộ đồ uống.' WHERE pr.store_name_ko = '브레댄코' AND p.description = '모닝세트: 아메리카노 + 샌드위치 3500원, 음료 전 메뉴 무료 사이즈업';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free instant ramen for orders of 20,000 KRW or more.', p.description_ja = '20,000ウォン以上の注文でインスタントラーメンを無料提供。', p.description_vi = 'Đơn từ 20.000 KRW trở lên được tặng ramen ăn liền.' WHERE pr.store_name_ko = '씨밤바베' AND p.description = '2만원 이상 주문 시 즉석 라면 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free mini nachos per table when ordering 4 or more cocktails.', p.description_ja = 'カクテル4杯以上注文時、テーブルごとにミニナチョスを無料提供。', p.description_vi = 'Gọi từ 4 ly cocktail trở lên được tặng nachos nhỏ cho mỗi bàn.' WHERE pr.store_name_ko = '가치' AND p.description = '칵테일 4잔 이상 주문시 테이블 당 미니 나초';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 bottle of soju for orders of 50,000 KRW or more.', p.description_ja = '50,000ウォン以上の注文で焼酎1本を無料提供。', p.description_vi = 'Đơn từ 50.000 KRW trở lên được tặng 1 chai soju.' WHERE pr.store_name_ko = '젠사이야' AND p.description = '5만원 이상 주문 시 소주 1병';
