UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free French Fries for orders of 40,000 KRW or more per table.', p.description_ja = '40,000ウォン以上の注文でフライドポテトを無料提供。', p.description_vi = 'Đơn từ 40.000 KRW trở lên được tặng khoai tây chiên.' WHERE pr.store_name_ko = '사랑과평화' AND p.description = '테이블당 4만원 이상 주문 시 감자튀김 서비스';
