UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Pay 10,000 KRW by bank transfer or cash to receive 10 hours plus 1 free drink.', p.description_ja = '現金または口座振込で10,000ウォンをチャージすると、10時間＋ドリンク1杯を提供。', p.description_vi = 'Nạp 10.000 KRW bằng tiền mặt hoặc chuyển khoản được tặng 10 giờ sử dụng và 1 đồ uống.' WHERE pr.store_name_ko = '에이플 PC방' AND p.description = '계좌이체 or 현금 1만원 충전 시 10시간 + 음료 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Set A, B, and C available at youth rates.', p.description_ja = 'Set A・B・Cは青少年料金で利用可能。', p.description_vi = 'Set A, B, C áp dụng giá thanh thiếu niên.' WHERE pr.store_name_ko = '놀숲' AND p.description = 'A B C 세트 청소년 요금제로 이용 가능';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Pay 10,000 KRW by bank transfer or cash at the counter, then text the owner “I’m a student of the College of Economics and International Commerce, and I recharged 10,000 KRW” to get 5 extra songs.', p.description_ja = 'カウンターで口座振込または現金で10,000ウォンをチャージ後、店主に学生認証メッセージを送ると5曲追加。', p.description_vi = 'Nạp 10.000 KRW bằng chuyển khoản hoặc tiền mặt tại quầy, sau đó nhắn tin xác minh sinh viên cho chủ quán để nhận thêm 5 bài hát.' WHERE pr.store_name_ko = '리코스타 코인노래방' AND p.description = '계좌이체 또는 현금 카운터 1만원 충전 후 사장님께 문자로 ''경통대 학생인데 1만원 충전했습니다'' 인증 시 5곡 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '5% off meat dishes when paying with Toss Pay.', p.description_ja = 'Toss Pay決済時、肉料理5%割引。', p.description_vi = 'Giảm 5% món thịt khi thanh toán bằng Toss Pay.' WHERE pr.store_name_ko = '먹돼지' AND p.description = '토스페이 결제 시 고기류 5% 할인';
