UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1.25L Pepsi Zero Lime for orders of 30,000 KRW or more. Dine-in or takeout only.', p.description_ja = '30,000ウォン以上の注文で1.25L ペプシゼロライムを無料提供。
 店内飲食またはテイクアウトのみ対象。', p.description_vi = 'Tặng 1.25L Pepsi Zero Lime cho đơn hàng từ 30.000 KRW trở lên.
 Chỉ áp dụng cho ăn tại chỗ hoặc mang đi.' WHERE pr.store_name_ko = '피자스쿨' AND p.description = '3만원 이상 주문(매장 식사, 포장) 시 펩시 제로 라임 1.25L 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For orders of 30,000 KRW or more, choose one: 2 drinks, soju, beer, or Youtiao. Up to 4 receipts may be combined.', p.description_ja = '30,000ウォン以上の注文で、ドリンク2本・焼酎・ビール・油条のうち1つを選択。レシートは最大4枚まで合算可能。
 レシートは最大4枚まで合算可能。', p.description_vi = 'Đơn từ 30.000 KRW trở lên được chọn 1 trong các món: 2 đồ uống, soju, bia hoặc quẩy Youtiao. Có thể gộp tối đa 4 hóa đơn.
 Có thể gộp tối đa 4 hóa đơn.' WHERE pr.store_name_ko = '샹츠마라' AND p.description = '3만원 이상 주문 시 음료수 2개 또는 소주 또는 맥주 또는 유토우 제공(합칠 수 있는 영수증 최대 4개)';
