UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For groups of 4 or more, choose either 1 free 500ml soft drink or 1 fried dumpling per person.', p.description_ja = '4人以上の来店で、500mlドリンク1本または1人につき焼き餃子1個のいずれかを提供。', p.description_vi = 'Nhóm từ 4 người trở lên chọn 1 ưu đãi: 1 nước ngọt 500ml hoặc 1 mandu chiên cho mỗi người.' WHERE pr.store_name_ko = '취향' AND p.description = '4인 이상 방문 시 음료 500ml 1개 또는 1인당 군만두 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free cheese add-on when ordering 2 or more servings of Dakgalbi.', p.description_ja = 'タッカルビ2人前以上注文時、チーズ追加を無料提供。', p.description_vi = 'Khi gọi từ 2 phần dakgalbi trở lên, được tặng phần phô mai thêm.' WHERE pr.store_name_ko = '코웍 비스트로' AND p.description = '닭갈비 2인분 이상 주문 시 치즈사리 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free drink when ordering 2 or more menu items per table. Excludes lunch hours from 12 PM to 2 PM and dinner hours from 5 PM to 7 PM.', p.description_ja = 'テーブルごとにメニュー2品以上注文時、ドリンクを提供。ランチ12〜14時、ディナー17〜19時は対象外。', p.description_vi = 'Tặng đồ uống khi mỗi bàn gọi từ 2 món trở lên. Không áp dụng giờ trưa 12 PM–2 PM và giờ tối 5 PM–7 PM.' WHERE pr.store_name_ko = '고추동제면소' AND p.description = '테이블당 메뉴 2개 이상 주문 시 음료 서비스(점심 12-2시, 저녁 17-19시 제외)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free soda when ordering 2 main dishes priced at 7,200 KRW or more.', p.description_ja = '7,200ウォン以上のメインメニュー2品注文時、炭酸飲料1杯を無料提供。', p.description_vi = 'Gọi 2 món chính giá từ 7.200 KRW trở lên được tặng 1 soda.' WHERE pr.store_name_ko = '샐러디' AND p.description = '메인메뉴(7,200원 이상) 2개 주문 시 탄산음료 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free Americano with any slice cake purchase.', p.description_ja = 'カットケーキ購入時、アメリカーノ1杯を無料提供。', p.description_vi = 'Mua miếng bánh kem được tặng 1 Americano.' WHERE pr.store_name_ko = '커피나무' AND p.description = '조각케이크 구매 시 아메리카노 1잔 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '1. Americano for 2,000 KRW when ordering through POS before 9 AM.
 2. Free size upgrade from L to J when purchasing 4 or more drinks on Mondays and Fridays.
 Excludes single-size menu items such as smoothies, crushes, Brown Sugar Jewelry, and Strawberry Jewelry.
 3. 10% off group orders of 10 drinks or more.
 Only applies to direct in-store POS payments.', p.description_ja = '1. 9時以前にPOS注文するとアメリカーノ2,000ウォン。
 2. 月・金曜日にドリンク4杯以上購入でL→Jサイズアップ無料。単一サイズメニューは対象外。
 3. ドリンク10杯以上の団体注文は10%割引。店頭POSでの直接決済のみ対象。プラットフォーム注文は対象外。', p.description_vi = '1. Americano giá 2.000 KRW khi đặt qua POS trước 9 AM.
 2. Mua từ 4 đồ uống vào thứ Hai và thứ Sáu được nâng size miễn phí từ L lên J. Không áp dụng cho món chỉ có một size.
 3. Giảm 10% cho đơn nhóm từ 10 đồ uống trở lên. Chỉ áp dụng khi thanh toán trực tiếp tại POS; không áp dụng cho đơn trên nền tảng.' WHERE pr.store_name_ko = '공차' AND p.description = '9시 이전 포스 주문 시 아메리카노 2000원 구매
월, 금요일 4잔 이상 구매 시 L -> J size up
(단일 사이즈메뉴는 제외-스무디, 크러쉬, 브라운슈가쥬얼리, 딸기쥬얼리 등등)
10잔 이상 단체 주문 시 10% 할인 (단, 현장 포스에서 결제 시에만 가능)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free extra shot once when ordering 2 drinks: 1 Big Americano plus 1 Iced Tea.', p.description_ja = 'ビッグサイズアメリカーノ1杯＋アイスティー1杯の計2杯注文時、1杯にショット1回無料追加。', p.description_vi = 'Gọi 2 đồ uống gồm 1 Americano cỡ lớn + 1 trà đá được thêm 1 shot miễn phí vào 1 ly.' WHERE pr.store_name_ko = '카페 봄봄' AND p.description = '2잔(빅 아메리카노, 아이스티 각각 1잔) 주문 시 샷 추가 1번 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For orders of 50,000 KRW or more, choose one: Garlic Butter Potato or Seasoned Fries.', p.description_ja = '50,000ウォン以上で、ガーリックバターポテトまたは味付けポテトのうち1つを選択。', p.description_vi = 'Từ 50.000 KRW trở lên được chọn 1 trong các món: khoai tây bơ tỏi hoặc khoai tây lắc gia vị.' WHERE pr.store_name_ko = '역전할머니맥주' AND p.description = '5만원 이상 주문 시 갈릭빠다포테이토 또는 양념감자 중 택 1 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '5% off when ordering 2 or more menu items and paying by cash, bank transfer, or KakaoPay.', p.description_ja = 'メニュー2品以上注文後、現金・口座振込・KakaoPay決済時5%割引。', p.description_vi = 'Gọi từ 2 món trở lên và thanh toán bằng tiền mặt, chuyển khoản hoặc KakaoPay được giảm 5%.' WHERE pr.store_name_ko = '인쌩맥주' AND p.description = '메뉴 2개 이상 주문 후 현금, 계좌이체 또는 카카오페이 결제 시 5% 할인';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free drink for orders of 30,000 KRW or more.', p.description_ja = '30,000ウォン以上の注文でドリンクを無料提供。', p.description_vi = 'Đơn từ 30.000 KRW trở lên được tặng đồ uống.' WHERE pr.store_name_ko = '파동추야' AND p.description = '3만원 이상 주문 시 음료 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free French Fries for orders of 40,000 KRW or more per table.', p.description_ja = '40,000ウォン以上の注文でフライドポテトを無料提供。', p.description_vi = 'Đơn từ 40.000 KRW trở lên được tặng khoai tây chiên.' WHERE pr.store_name_ko = '사랑과평화' AND p.description = '테이블 당 4만원 이상 주문 시 감자튀김 서비스';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free French Fries once per table when ordering 2 or more highballs or yangmaek drinks.', p.description_ja = 'テーブルごとに1回、ハイボールまたはヤンメクを2杯以上注文時、フライドポテトを無料提供。', p.description_vi = 'Mỗi bàn được tặng khoai tây chiên 1 lần khi gọi từ 2 ly highball hoặc yangmaek trở lên.' WHERE pr.store_name_ko = '자월당' AND p.description = '테이블 당 1회 하이볼 또는 양맥 2잔 이상 주문 시 감자튀김 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Pay for 9 hours by cash or bank transfer and receive 10 hours plus 1 free drink.', p.description_ja = '現金または口座振込で9時間分を決済すると、10時間＋ドリンク1杯を提供。', p.description_vi = 'Thanh toán 9 giờ bằng tiền mặt hoặc chuyển khoản được tặng 10 giờ sử dụng và 1 đồ uống.' WHERE pr.store_name_ko = '에이플 PC방' AND p.description = '9시간 현금 결제 또는 계좌 이체 충전 시 10시간 + 음료 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Set A, B, and C available at youth rates.', p.description_ja = 'Set A・B・Cは青少年料金で利用可能。', p.description_vi = 'Set A, B, C áp dụng giá thanh thiếu niên.' WHERE pr.store_name_ko = '놀숲' AND p.description = '세트 A, B, C 요금제를 성인 -> 청소년으로 변경';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Pay 10,000 KRW by bank transfer or cash at the counter, then text the owner “I’m a student of the School of Liberal Studies, and I recharged 10,000 KRW” to get 5 extra songs.', p.description_ja = 'カウンターで口座振込または現金で10,000ウォンをチャージ後、店主に学生認証メッセージを送ると5曲追加。', p.description_vi = 'Nạp 10.000 KRW bằng chuyển khoản hoặc tiền mặt tại quầy, sau đó nhắn tin xác minh sinh viên cho chủ quán để nhận thêm 5 bài hát.' WHERE pr.store_name_ko = '리코스타 코인노래방' AND p.description = '계좌이체 또는 카운터 현금 1만원 충전 후 사장님께 문자로 "자전 재학생인데 1만원 충전했습니다." 인증 시 5곡 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For groups of 1–2, get 1 free drink. For groups of 3–4, get 2 free drinks.', p.description_ja = '1〜2人でドリンク1杯を無料提供。
 3〜4人で2 ドリンクを無料提供。', p.description_vi = 'Nhóm 1–2 người được tặng 1 đồ uống.
 Nhóm 3–4 người được tặng 2 đồ uống.' WHERE pr.store_name_ko = '면식당' AND p.description = '2인 이하 음료 1개 / 3~4인 음료 2개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For purchases of 30,000 KRW or more, choose one: Bing Hong Cha, Cha Pai, or 3 pieces of Youtiao. Up to 3 receipts may be combined.', p.description_ja = '30,000ウォン以上の購入で、油条3個・茶π・冰紅茶のうち1つを選択。レシートは最大3枚まで合算可能。
 レシートは最大3枚まで合算可能。', p.description_vi = 'Đơn mua từ 30.000 KRW trở lên được chọn 1 trong các món: 3 miếng quẩy Youtiao, Cha Pai hoặc Bing Hong Cha. Có thể gộp tối đa 3 hóa đơn.
 Có thể gộp tối đa 3 hóa đơn.' WHERE pr.store_name_ko = '샹츠마라' AND p.description = '30,000원 이상 구매 시(영수증 3개 이하 합산 가능) 빙홍차 또는 차파이, 유토우 3p 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For orders of 20,000 KRW or more, get 2 free drinks. For orders of 30,000 KRW or more, upgrade all menu items to set menus.', p.description_ja = '20,000ウォン以上の注文でドリンク2杯を無料提供。
 30,000ウォン以上の注文で全メニューをセットメニューに変更。', p.description_vi = 'Đơn từ 20.000 KRW trở lên được tặng 2 đồ uống.
 Đơn từ 30.000 KRW trở lên được nâng toàn bộ menu thành set menu.' WHERE pr.store_name_ko = '지지고' AND p.description = '20,000원 이상 주문 시 음료 2개 제공
30,000원 이상 주문 시 모든 메뉴 세트로 변경';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '5% off when paying with KakaoPay, Toss Pay, or bank transfer for grilled dishes.', p.description_ja = '焼き物注文時、KakaoPay・Toss Pay・口座振込決済で5%割引。', p.description_vi = 'Giảm 5% món nướng khi thanh toán bằng KakaoPay, Toss Pay hoặc chuyển khoản.' WHERE pr.store_name_ko = '먹돼지' AND p.description = '구이류 주문 시 카카오페이/토스페이/계좌이체 시 5% 할인';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For set purchases of 13,000 KRW or more, add 1 scoop of Egg Mayo or 1 strip of bacon.', p.description_ja = '13,000ウォン以上のセット購入時、エッグマヨ1スクープまたはベーコン1枚を追加提供。', p.description_vi = 'Mua set từ 13.000 KRW trở lên được thêm 1 muỗng Egg Mayo hoặc 1 lát bacon.' WHERE pr.store_name_ko = '써브웨이' AND p.description = '13,000원 이상 세트 구매 시 에그마요 1스쿱 또는 베이컨 1줄 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 500ml soft drink per table for orders of 75,000 KRW or more for groups of up to 4, or 85,000 KRW or more for groups of 5 or more.', p.description_ja = '1テーブルにつき、4人以下は75,000ウォン以上、5人以上は85,000ウォン以上の注文で500mlドリンク1本を無料提供。', p.description_vi = 'Mỗi bàn được tặng 1 đồ uống 500ml khi nhóm tối đa 4 người gọi từ 75.000 KRW trở lên, hoặc nhóm từ 5 người gọi từ 85.000 KRW trở lên.' WHERE pr.store_name_ko = '청운음식점' AND p.description = '한 테이블당 4인 이하 75,000원 / 5인 이상 85,000원 이상 주문 시 500ml 음료 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free drink for groups of 4 or more.', p.description_ja = '4人以上の来店でドリンクを無料提供。', p.description_vi = 'Nhóm từ 4 người trở lên được tặng đồ uống.' WHERE pr.store_name_ko = '파라다이스' AND p.description = '4인 이상 방문 시 음료 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free drink for groups of 3 or more with orders of 20,000 KRW or more.', p.description_ja = '3人以上の来店かつ20,000ウォン以上の注文でドリンク1杯を無料提供。', p.description_vi = 'Nhóm từ 3 người trở lên và đơn từ 20.000 KRW trở lên được tặng 1 đồ uống.' WHERE pr.store_name_ko = '왕돈까스왕냉면' AND p.description = '3인 이상 방문 및 20,000원 이상 주문 시 음료 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For groups of 4 or more, get 1 free drink. Or, for groups of 4 or more spending 50,000 KRW or more, get 1 free bottle of soju.', p.description_ja = '4人以上でドリンク1杯を無料提供。
 また、4人以上で50,000ウォン以上利用時、焼酎1本を無料提供。', p.description_vi = 'Nhóm từ 4 người trở lên được tặng 1 đồ uống.
 Hoặc nhóm từ 4 người trở lên chi từ 50.000 KRW trở lên được tặng 1 chai soju.' WHERE pr.store_name_ko = '신의주찹쌀순대' AND p.description = '4인 이상 주문 시 음료 1개 제공 / 4인 이상 방문하여 50,000원 이상 주문 시 소주 1병 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Add 30g of chicken breast or smoked duck topping when ordering a main menu item.', p.description_ja = 'メインメニュー注文時、鶏むね肉または燻製鴨トッピング30gを追加提供。', p.description_vi = 'Khi gọi món chính, được thêm 30g topping ức gà hoặc vịt hun khói.' WHERE pr.store_name_ko = '포케올데이' AND p.description = '메인 메뉴 주문 시 닭가슴살 또는 훈제오리 토핑 30g 추가';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '1 free drink for every 3 people.', p.description_ja = '3人ごとにドリンク1本無料。', p.description_vi = 'Tặng 1 đồ uống cho mỗi 3 người.' WHERE pr.store_name_ko = '삼봉버거' AND p.description = '3인당 음료 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 bottle of soju for purchases of 40,000 KRW or more.', p.description_ja = '40,000ウォン以上の購入で焼酎1本を無料提供。', p.description_vi = 'Mua từ 40.000 KRW trở lên được tặng 1 chai soju.' WHERE pr.store_name_ko = '숯가마 바베큐 치킨' AND p.description = '40,000원 이상 구매 시 소주 1병 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free fried dumplings for groups of 4 or more.', p.description_ja = '4人以上の来店で焼き餃子を無料提供。', p.description_vi = 'Nhóm từ 4 người trở lên được tặng mandu chiên.' WHERE pr.store_name_ko = '황궁쟁반짜장' AND p.description = '4인 이상 방문 시 군만두 무료 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '1 free drink for every 2 people.', p.description_ja = '1人1メニュー注文時、2人ごとにドリンク1本無料。例：4人の場合は2本。', p.description_vi = 'Khi mỗi người gọi 1 món, tặng 1 đồ uống cho mỗi 2 người. Ví dụ: 4 người được 2 đồ uống.' WHERE pr.store_name_ko = '멘동' AND p.description = '2인당 음료 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For groups of 3, get 1 free drink. For groups of 4 or more, get 2 free drinks.', p.description_ja = '3人でドリンク1杯を無料提供。
 4人以上で2 ドリンクを無料提供。', p.description_vi = 'Nhóm 3 người được tặng 1 đồ uống.
