UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For orders of 50,000 KRW or more, choose one: Pineapple Sherbet or Garlic Butter Potato.', p.description_ja = '50,000ウォン以上で、パイナップルシャーベットまたはガーリックバターポテトのうち1つを選択。', p.description_vi = 'Từ 50.000 KRW trở lên được chọn 1 trong các món: sorbet dứa hoặc khoai tây bơ tỏi.' WHERE pr.store_name_ko = '역전할머니맥주' AND p.description = '50,000원 이상 주문 시 파인애플 샤베트 or 갈릭버터 포테이토 중 택 1 증정';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free bottled soft drink per table.', p.description_ja = 'テーブルごとにボトル飲料を無料提供。', p.description_vi = 'Tặng nước ngọt đóng chai cho mỗi bàn.' WHERE pr.store_name_ko = '리얼 후라이' AND p.description = '테이블 당 음료수 1병 증정';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For cash payments of 70,000 KRW or more, choose one: Kimchi Fried Rice, Rolled Omelet, or Cocktail Soju (420ml).', p.description_ja = '70,000ウォン以上の現金決済で、キムチチャーハン・卵焼き・カクテル焼酎（420ml）のうち1つを選択。', p.description_vi = 'Thanh toán tiền mặt từ 70.000 KRW trở lên được chọn 1 món: cơm chiên kimchi, trứng cuộn hoặc soju cocktail 420ml.' WHERE pr.store_name_ko = '블루힐' AND p.description = '70,000원 이상 현금 결제 시 김치볶음밥 or 계란말이 or 칵테일 소주(420ml) 택 1 증정';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Visit before 6 PM to receive 1 bottle of soju or Soft Tofu Stew.', p.description_ja = '18時以前の来店で、焼酎1本またはスンドゥブチゲを無料提供。', p.description_vi = 'Đến trước 6 PM được tặng 1 chai soju hoặc canh đậu phụ non.' WHERE pr.store_name_ko = '28청춘호프포차' AND p.description = '18시 이전 매장 방문 시 소주 1병 or 순두부 찌개 증정';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free French Fries for orders of 40,000 KRW or more.', p.description_ja = '40,000ウォン以上の注文でフライドポテトを無料提供。', p.description_vi = 'Đơn từ 40.000 KRW trở lên được tặng khoai tây chiên.' WHERE pr.store_name_ko = '사랑과평화' AND p.description = '40,000원 이상 주문 시 감자튀김 증정';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Get a free soda when adding 5,000 KRW of credit. Get a free café drink when adding 10,000 KRW of credit.', p.description_ja = '5,000ウォンチャージで炭酸飲料を無料提供。
 10,000ウォンチャージでカフェドリンクを無料提供。', p.description_vi = 'Nạp 5.000 KRW được tặng soda.
 Nạp 10.000 KRW được tặng đồ uống cà phê.' WHERE pr.store_name_ko = '긱스타 PC방' AND p.description = '5,000원 시간 충전 시 탄산음료 증정 및 10,000원 시간 충전 시 카페음료 증정';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Set A, B, and C available at youth rates: Set A 5,500 KRW, Set B 8,500 KRW, Set C 10,500 KRW.', p.description_ja = 'Set A・B・Cは青少年料金で利用可能：Set A 5,500ウォン、Set B 8,500ウォン、Set C 10,500ウォン。', p.description_vi = 'Set A, B, C áp dụng giá thanh thiếu niên: Set A 5.500 KRW, Set B 8.500 KRW, Set C 10.500 KRW.' WHERE pr.store_name_ko = '놀숲' AND p.description = '세트 A, B, C를 청소년 이용금액으로 적용
set A 5,500원
set B 8,500원
set C 10,500원';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '15% off game fees.', p.description_ja = 'ゲーム料金15%割引。', p.description_vi = 'Giảm 15% phí chơi game.' WHERE pr.store_name_ko = '히어로 보드게임 카페' AND p.description = '게임 비용 15% 할인';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free gimmari fried seaweed roll topping with Physics Department student ID.', p.description_ja = '物理学科の学生証提示でキムマリトッピングを無料提供。', p.description_vi = 'Xuất trình thẻ sinh viên Khoa Vật lý được tặng topping gimmari.' WHERE pr.store_name_ko = '고씨네' AND p.description = '물리학과 학생증 제시하면 김말이 토핑 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'After visiting with 4 people and showing student ID, choose one per table: 4 fried dumplings or 1 soda.', p.description_ja = '4人で来店し学生証を提示すると、テーブルごとに焼き餃子4個または炭酸飲料1本のいずれかを提供。', p.description_vi = 'Nhóm 4 người đến và xuất trình thẻ sinh viên được chọn 1 ưu đãi cho mỗi bàn: 4 mandu chiên hoặc 1 soda.' WHERE pr.store_name_ko = '취향' AND p.description = '4인 방문 후 학생증 제시하면 군만두 4개 or 탄산음료 테이블 당 1개';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Pay 10,000 KRW to get 5 extra songs. Student ID verification with phone number and recharge amount verification required.', p.description_ja = '10,000ウォンチャージで5曲追加。携帯番号での学生証確認とチャージ金額の認証が必要。', p.description_vi = 'Nạp 10.000 KRW được thêm 5 bài hát. Cần xác minh thẻ sinh viên bằng số điện thoại và xác minh số tiền nạp.' WHERE pr.store_name_ko = '리코스타 코인 노래방' AND p.description = '1만원 충전 시, 5곡 서비스 (휴대폰 번호로 학생증 제시, 충전 금액 인증)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '5% off when paying by bank transfer or cash.', p.description_ja = '口座振込または現金決済時、5%割引。', p.description_vi = 'Giảm 5% khi thanh toán bằng chuyển khoản hoặc tiền mặt.' WHERE pr.store_name_ko = '상도로 3가' AND p.description = '계좌이체 or 현금결제 시 5% 할인';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free canned drinks based on group size: 1 can for 3 people, 2 cans for 6 people, and 3 cans for 9 people.', p.description_ja = '人数に応じて缶飲料を無料提供：3人は1缶、6人は2缶、9人は3缶。', p.description_vi = 'Tặng nước lon theo số người/khẩu phần: 1 lon cho 3 người, 2 lon cho 6 người, 3 lon cho 9 người.' WHERE pr.store_name_ko = '삼봉버거' AND p.description = '3인 방문 시, 음료 1캔 증정 
6인 방문 시, 음료 2캔 증정 
9인 방문 시, 음료 3캔 증정';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'When each person orders 1 menu item: 1 free canned soft drink for groups of 2 or more, or 2 free canned soft drinks for groups of 4 or more.', p.description_ja = '1人1メニュー注文時、2人以上は缶飲料1本、4人以上は缶飲料2本を提供。', p.description_vi = 'Khi mỗi người gọi 1 món: nhóm từ 2 người được tặng 1 lon nước ngọt, nhóm từ 4 người được tặng 2 lon.' WHERE pr.store_name_ko = '멘동' AND p.description = '1인 1메뉴 주문 시 2인 이상 음료수 1캔 / 4인 이상 음료수 2캔 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For orders of 30,000 KRW or more, choose one: Youtiao, Cha Pai, or Bing Hong Cha. Up to 3 receipts may be combined.', p.description_ja = '30,000ウォン以上の注文で、油条・茶π・冰紅茶のうち1つを選択。レシートは最大3枚まで合算可能。
 レシートは最大3枚まで合算可能。', p.description_vi = 'Đơn từ 30.000 KRW trở lên được chọn 1 trong các món: quẩy Youtiao, Cha Pai hoặc Bing Hong Cha. Có thể gộp tối đa 3 hóa đơn.
 Có thể gộp tối đa 3 hóa đơn.' WHERE pr.store_name_ko = '샹츠마라' AND p.description = '3만원 이상 주문 시 유토우 또는 음료(차파이/빙홍차) 중 1개 제공 (영수증 최대 3개까지만 취합 가능)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free topping add-on for burrito orders, excluding bacon.', p.description_ja = 'ブリトー注文時、ベーコンを除くトッピング1つ無料。', p.description_vi = 'Gọi burrito được thêm 1 topping miễn phí, trừ bacon.' WHERE pr.store_name_ko = '밀플랜비' AND p.description = '부리또 주문 시 토핑 1개 무료(베이컨 제외)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 500ml soft drink per table for orders of 75,000 KRW or more for groups of up to 4, or 85,000 KRW or more for groups of up to 5.', p.description_ja = '4人以下は75,000ウォン以上、5人以上は85,000ウォン以上の注文で、テーブルごとに500mlドリンク1本を無料提供。', p.description_vi = 'Tặng 1 nước ngọt 500ml cho mỗi bàn với đơn từ 75.000 KRW cho nhóm tối đa 4 người, hoặc từ 85.000 KRW cho nhóm từ 5 người trở lên.' WHERE pr.store_name_ko = '청운음식점' AND p.description = '한 테이블에 4인 이하 방문 후 7만 5천원 이상 주문 시 또는 한 테이블에 5인 이하 방문 후 8만 5천원 이상 주문 시 음료 1개(500ml) 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '5% off when paying with KakaoPay, applicable to meat dishes only.', p.description_ja = 'KakaoPay決済時、肉料理5%割引。', p.description_vi = 'Giảm 5% món thịt khi thanh toán bằng KakaoPay.' WHERE pr.store_name_ko = '먹돼지' AND p.description = '카카오페이로 결제 시 5% 할인 (고기류 주문 시에만 해당)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free French Fries when 2 people visit and order 2 or more chickens.', p.description_ja = '2名で来店しチキン2羽以上注文時、フライドポテトを無料提供。', p.description_vi = '2 người đến và gọi từ 2 phần gà nguyên con trở lên được tặng khoai tây chiên.' WHERE pr.store_name_ko = '미쳐버린 파닭' AND p.description = '2인 방문 후 두 마리 이상 주문 시 감자튀김 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For orders of 50,000 KRW or more, choose one: 1 bottle of soju (Chamisul/Cheoeumcheoreom) or Garlic Butter Potato.', p.description_ja = '50,000ウォン以上の注文で、焼酎1本（チャミスル/チョウムチョロム）またはガーリックバターポテトのうち1つを選択。', p.description_vi = 'Đơn từ 50.000 KRW trở lên được chọn 1 món: 1 chai soju (Chamisul/Cheoeumcheoreom) hoặc khoai tây bơ tỏi.' WHERE pr.store_name_ko = '역전할머니맥주' AND p.description = '5만원 이상 주문 시 소주 한 병(참이슬/처음처럼) 또는 갈릭빠다포테이토 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free canned soft drink for orders of 40,000 KRW or more.', p.description_ja = '40,000ウォン以上の注文で缶ドリンクを無料提供。', p.description_vi = 'Đơn từ 40.000 KRW trở lên được tặng nước ngọt đóng lon.' WHERE pr.store_name_ko = '파동추야' AND p.description = '4만원 이상 주문 시 음료수 1캔 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 canned soft drink per table.', p.description_ja = 'テーブルごとに1 缶飲料を無料提供。', p.description_vi = 'Tặng 1 nước ngọt đóng lon cho mỗi bàn.' WHERE pr.store_name_ko = '리얼후라이' AND p.description = '테이블 당 음료수 1캔 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = '10% off per table when writing a Naver receipt review. Payment must be made at the POS, not the kiosk.', p.description_ja = 'Naverレシートレビュー作成時、テーブルごとに 10%割引。
 キオスクではなくPOSでの決済が必要。', p.description_vi = 'Giảm 10% cho mỗi bàn khi viết đánh giá hóa đơn Naver.
 Phải thanh toán tại POS, không áp dụng khi thanh toán bằng kiosk.' WHERE pr.store_name_ko = '미태리' AND p.description = '네이버 영수증 리뷰 작성 시 테이블 한 곳 당 10% 할인 (키오스크가 아닌 포스기에서 결제하여야 함)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Free 1 gimmari fried seaweed roll with AI College student ID verification. One fried seaweed roll per verified student. Please verify the partnership and request it immediately after ordering. Requests made after some time may be declined.', p.description_ja = 'AI大学の学生証認証時、キムマリ1個を無料提供。認証した学生1名につき1個提供。注文直後に提携認証を行い、キムマリをお申し出ください。時間が経過した後の申し出は断られる場合があります。', p.description_vi = 'Xác minh thẻ sinh viên College of AI được tặng 1 gimmari. Mỗi sinh viên đã xác minh được 1 cái. Vui lòng xác minh ưu đãi và yêu cầu gimmari ngay sau khi gọi món; yêu cầu muộn có thể bị từ chối.' WHERE pr.store_name_ko = '고씨네' AND p.description = 'AI대학 학생증 인증 시 김말이 1개 제공 (학생증 인증 N명당 N개 제공) (주문 직후 제휴 인증하고 김말이 요청해야 함. 주문 시간 경과 후 제휴 요청 시 거절할 수 있음)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Get a free soda when adding 5,000 KRW of credit. Choose one free drink when adding 10,000 KRW of credit: soda, Americano, or iced tea.', p.description_ja = '5,000ウォンチャージで炭酸飲料1杯を無料提供。
 10,000ウォンチャージで炭酸飲料・アメリカーノ・アイスティーのうち1杯を無料提供。', p.description_vi = 'Nạp 5.000 KRW được tặng 1 soda.
 Nạp 10.000 KRW được chọn 1 đồ uống miễn phí: soda, Americano hoặc trà đá.' WHERE pr.store_name_ko = '긱스타 PC방' AND p.description = '5,000원 충전 시 탄산음료 1개 제공 / 10,000원 충전 시 탄산음료, 아메리카노, 아이스티 중 1개 제공';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'Pay 10,000 KRW by cash or bank transfer to receive 10 hours plus 1 free drink. Drink options: iced tea, dabang-style coffee, Americano, or soda.', p.description_ja = '現金または口座振込で10,000ウォンをチャージすると、10時間＋ドリンク1杯を提供。 ドリンクはアイスティー・ダバンコーヒー・アメリカーノ・炭酸飲料から選択。', p.description_vi = 'Nạp 10.000 KRW bằng tiền mặt hoặc chuyển khoản được tặng 10 giờ sử dụng và 1 đồ uống. Có thể chọn đồ uống: trà đá, cà phê kiểu dabang, Americano hoặc soda.' WHERE pr.store_name_ko = '에이플 PC방' AND p.description = '현금 또는 계좌이체 10,000원 충전 시 10시간+음료증정(아이스티/다방커피/아메리카노/탄산)';
UPDATE partnership p JOIN partnership_restaurant pr ON p.partnership_restaurant_id = pr.partnership_restaurant_id SET p.description_en = 'For groups of 1–2, get 1 canned soft drink. For groups of 3–4, get 2 canned soft drinks.', p.description_ja = '1〜2人で缶ドリンク1本を無料提供。
 3〜4人で2 缶ドリンクを無料提供。', p.description_vi = 'Nhóm 1–2 người được tặng 1 lon nước ngọt.
 Nhóm 3–4 người được tặng 2 nước ngọt đóng lon.' WHERE pr.store_name_ko = '면식당' AND p.description = '2인 이하 방문 시 음료수 1캔 / 3~4인 방문 시 음료수 2캔 제공';
